// ---------- State ----------
abstract class DataState extends Equatable {
  const DataState();
  @override List<Object?> get props => [];
}

class DataInitial extends DataState {}
class DataLoading extends DataState {}
class DataLoaded extends DataState {
  final String data;
  const DataLoaded(this.data);
  @override List<Object?> get props => [data];
}
class DataError extends DataState {
  final String message;
  const DataError(this.message);
  @override List<Object?> get props => [message];
}

// ---------- Events ----------
abstract class DataEvent extends Equatable {
  const DataEvent();
  @override List<Object?> get props => [];
}

class LoadData extends DataEvent {}

// ---------- BLoC ----------
class DataBloc extends Bloc<DataEvent, DataState> {
  DataBloc() : super(DataInitial()) {
    on<LoadData>((event, emit) async {
      emit(DataLoading());
      await Future.delayed(Duration(seconds: 1));
      emit(DataLoaded('Hello from initial state! 👋'));
    });
  }
}

// ---------- UI ----------
class DataPage extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Initial State Demo')),
      body: BlocBuilder<DataBloc, DataState>(
        builder: (context, state) {
          if (state is DataInitial) {
            return Center(
              child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Text('Initial state: DataInitial', style: TextStyle(fontSize: 18)),
                  SizedBox(height: 20),
                  ElevatedButton(
                    onPressed: () => context.read<DataBloc>().add(LoadData()),
                    child: Text('Load Data'),
                  ),
                ],
              ),
            );
          } else if (state is DataLoading) {
            return Center(child: CircularProgressIndicator());
          } else if (state is DataLoaded) {
            return Center(
              child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Text('Loaded: ${state.data}', style: TextStyle(fontSize: 24)),
                  SizedBox(height: 20),
                  ElevatedButton(
                    onPressed: () => context.read<DataBloc>().add(LoadData()),
                    child: Text('Reload'),
                  ),
                ],
              ),
            );
          } else if (state is DataError) {
            return Center(
              child: Column(
                mainAxisAlignment: MainAxisAlignment.center,
                children: [
                  Text('Error: ${state.message}'),
                  ElevatedButton(
                    onPressed: () => context.read<DataBloc>().add(LoadData()),
                    child: Text('Retry'),
                  ),
                ],
              ),
            );
          }
          return Container();
        },
      ),
    );
  }
}
